import React, { useState, useRef } from 'react';
import { View, ScrollView } from 'react-native';
import {
  Text,
  Button,
  Box,
  InputBox,
  Alert,
  Icon,
  ListTextIcon,
  SeparatorHorizontal,
  BackDropBottom,
  Loading,
} from '@semparar/design-system-app';
import type { Meta, StoryObj } from 'storybook/internal/types';

function StatusBadge({ status }: { status: 'ok' | 'fail' | 'warn' }) {
  const colors = { ok: '#22c55e', fail: '#ef4444', warn: '#f59e0b' };
  const labels = { ok: 'RENDERS', fail: 'FAILS', warn: 'PARTIAL' };
  return (
    <View
      style={{
        backgroundColor: colors[status],
        paddingHorizontal: 8,
        paddingVertical: 2,
        borderRadius: 4,
        alignSelf: 'flex-start',
        marginBottom: 8,
      }}
    >
      <Text type="bodySM" color="INTENSE_COLOR_01">
        {labels[status]}
      </Text>
    </View>
  );
}

function Section({
  title,
  children,
}: {
  title: string;
  children: React.ReactNode;
}) {
  return (
    <View style={{ marginBottom: 32 }}>
      <Text type="subtitleXXL" mb="smaller">
        {title}
      </Text>
      <Box
        pd="squishSmall"
        bgColor="LIGHT_BASE_02"
        br="sm"
        bw="thin"
        borderColor="BRAND_COMPLEMENT_02"
      >
        {children}
      </Box>
    </View>
  );
}

function TextValidation() {
  return (
    <Section title="1. Text">
      <StatusBadge status="ok" />
      <Text type="headingMDL" mb="nano">
        headingMDL — Form titles
      </Text>
      <Text type="subtitleXXL" mb="nano">
        subtitleXXL — Section headings
      </Text>
      <Text type="bodyMD" mb="nano">
        bodyMD — Body text
      </Text>
      <Text type="paragraphMD" mb="nano">
        paragraphMD — Descriptions
      </Text>
      <Text type="bodySM" mb="nano" color="INTENSE_COLOR_03">
        bodySM + color — Secondary text
      </Text>
      <Text
        type="bodyMD"
        color="PRYMARY_BASE_02"
        underline
        onPress={() => {}}
      >
        Pressable + underline — Link style
      </Text>
    </Section>
  );
}

function ButtonValidation() {
  return (
    <Section title="2. Button">
      <StatusBadge status="ok" />
      <Button text="Primary Large (default)" onPress={() => {}} mb="nano" />
      <Button
        text="Disabled State"
        onPress={() => {}}
        disabled
        mb="nano"
      />
      <Button
        text="With Icon"
        onPress={() => {}}
        icon="icon-check"
        mb="nano"
      />
      <Button
        text="Loading State"
        onPress={() => {}}
        isLoading
      />
    </Section>
  );
}

function BoxValidation() {
  return (
    <Section title="3. Box">
      <StatusBadge status="ok" />
      <Box
        pd="squishSmall"
        bgColor="PRYMARY_BASE_01"
        br="md"
        mb="nano"
      >
        <Text type="bodySM" color="INTENSE_COLOR_01">
          Box with bgColor, padding, borderRadius
        </Text>
      </Box>
      <Box direction align="center" mb="nano">
        <Box
          pd="squishSmall"
          bgColor="LIGHT_BASE_02"
          br="sm"
          mr="nano"
          flex={1}
        >
          <Text type="bodySM">Row item 1</Text>
        </Box>
        <Box pd="squishSmall" bgColor="LIGHT_BASE_02" br="sm" flex={1}>
          <Text type="bodySM">Row item 2</Text>
        </Box>
      </Box>
      <Box
        pd="innerMedium"
        bw="thin"
        borderColor="BRAND_COMPLEMENT_02"
        br="sm"
      >
        <Text type="bodySM">Box with border</Text>
      </Box>
    </Section>
  );
}

function InputBoxValidation() {
  const [value1, setValue1] = useState('');
  const [value2, setValue2] = useState('');
  const [value3, setValue3] = useState('');

  return (
    <Section title="4. InputBox">
      <StatusBadge status="ok" />
      <InputBox
        label="Valor em pontos"
        placeholder="0"
        showLabel
        keyboardType="number-pad"
        value={value1}
        onChangeText={setValue1}
        mb="nano"
      />
      <InputBox
        label="Valor em reais"
        placeholder="R$ 0,00"
        showLabel
        keyboardType="decimal-pad"
        value={value2}
        onChangeText={setValue2}
        textRight="Usar todos"
        onPressTextRight={() => setValue2('100')}
        mb="nano"
      />
      <InputBox
        label="With error"
        placeholder="Type something"
        showLabel
        value={value3}
        onChangeText={setValue3}
        error
        textError="Valor excede o saldo disponível"
      />
    </Section>
  );
}

function AlertValidation() {
  return (
    <Section title="5. Alert">
      <StatusBadge status="ok" />
      <Alert
        label="O valor é aplicado e exibido nos lançamentos da sua fatura aberta."
        type="highlight"
        icon="icon-calendar"
        mb="nano"
      />
      <Alert
        label="Resgate realizado com sucesso!"
        type="success"
        icon="icon-check"
        mb="nano"
      />
      <Alert
        label="Erro ao processar sua solicitação."
        type="error"
        icon="icon-help"
        mb="nano"
      />
      <Alert
        label="Atenção: valor mínimo de 100 pontos."
        type="alert"
        icon="icon-help"
      />
    </Section>
  );
}

function IconValidation() {
  return (
    <Section title="6. Icon">
      <StatusBadge status="ok" />
      <Box direction align="center" mb="nano">
        <Icon name="icon-check" size="md" color="PRYMARY_BASE_02" mr="nano" />
        <Icon
          name="icon-calendar"
          size="md"
          color="BRAND_BASE_01"
          mr="nano"
        />
        <Icon name="icon-help" size="md" color="INTENSE_COLOR_05" mr="nano" />
        <Icon
          name="icon-switch-vertical"
          size="md"
          color="INTENSE_COLOR_03"
        />
      </Box>
      <Box direction align="center">
        <Icon
          name="icon-check"
          size="sm"
          color="BRAND_BASE_01"
          hasBackground
          backgroundType="circle"
          bgColorCircle="INTENSE_COLOR_01"
          hasBackgroundCircle
          mr="nano"
        />
        <Text type="bodySM">Icon with circle background</Text>
      </Box>
    </Section>
  );
}

function ListTextIconValidation() {
  return (
    <Section title="7. ListTextIcon">
      <StatusBadge status="ok" />
      <ListTextIcon
        items={[
          {
            icon: 'icon-switch-vertical',
            iconColor: 'BRAND_BASE_01',
            iconColorShape: 'INTENSE_COLOR_01',
            description: 'Cada 100 pontos valem R$ 1,00 no voucher',
            hasBackgroundIcon: true,
          },
          {
            icon: 'icon-calendar',
            iconColor: 'BRAND_BASE_01',
            iconColorShape: 'INTENSE_COLOR_01',
            description: 'Você define quanto desconto quer no abastecimento',
            hasBackgroundIcon: true,
          },
          {
            icon: 'icon-check',
            iconColor: 'BRAND_BASE_01',
            iconColorShape: 'INTENSE_COLOR_01',
            description: 'Após o resgate, o voucher fica disponível no app',
            hasBackgroundIcon: true,
          },
        ]}
        type="list"
      />
    </Section>
  );
}

function SeparatorValidation() {
  return (
    <Section title="8. SeparatorHorizontal">
      <StatusBadge status="ok" />
      <Text type="bodySM" mb="nano">
        Content before separator
      </Text>
      <SeparatorHorizontal
        mb="nano"
        mt="nano"
        bgColor="BRAND_COMPLEMENT_02"
        height={1}
        width="100%"
      />
      <Text type="bodySM">Content after separator</Text>
    </Section>
  );
}

function BackDropBottomValidation() {
  return (
    <Section title="9. BackDropBottom">
      <StatusBadge status="warn" />
      <Text type="bodySM" color="INTENSE_COLOR_03" mb="nano">
        BackDropBottom depends on react-native-modalize which requires native
        modules (GestureHandler, Animated). It will NOT render in the Storybook
        web context. Use a plain View/ScrollView wrapper as substitute for
        SDUI stories.
      </Text>
    </Section>
  );
}

function LoadingValidation() {
  return (
    <Section title="10. Loading">
      <StatusBadge status="warn" />
      <Text type="bodySM" color="INTENSE_COLOR_03" mb="nano">
        Loading depends on lottie-react-native which requires native Lottie
        bindings. It will NOT render in the Storybook web context. Use a
        simple ActivityIndicator or Text fallback for SDUI stories.
      </Text>
    </Section>
  );
}

function DSComponentValidation() {
  return (
    <ScrollView style={{ flex: 1 }}>
      <View style={{ padding: 24, maxWidth: 480 }}>
        <Text type="headingMDL" mb="smaller">
          DS Component Validation — SP_0001.1
        </Text>
        <Text type="bodyMD" mb="smaller" color="INTENSE_COLOR_03">
          Validates all @semparar/design-system-app components used in voucher
          screens. Each section shows the component with realistic props matching
          InvoiceCashback screen usage.
        </Text>
        <SeparatorHorizontal
          mb="smaller"
          bgColor="BRAND_COMPLEMENT_02"
          height={1}
          width="100%"
        />
        <TextValidation />
        <ButtonValidation />
        <BoxValidation />
        <InputBoxValidation />
        <AlertValidation />
        <IconValidation />
        <ListTextIconValidation />
        <SeparatorValidation />
        <BackDropBottomValidation />
        <LoadingValidation />

        <Box pd="squishSmall" bgColor="LIGHT_BASE_02" br="sm" mt="smaller">
          <Text type="subtitleXXL" mb="nano">
            Summary
          </Text>
          <Text type="bodyMD" mb="nano">
            8/10 components render correctly in Storybook web context.
          </Text>
          <Text type="bodySM" color="INTENSE_COLOR_03">
            BackDropBottom (Modalize) and Loading (Lottie) require native modules
            and cannot render on web. SDUI adapters should provide web-safe
            fallbacks for these two components.
          </Text>
        </Box>
      </View>
    </ScrollView>
  );
}

const meta: Meta<typeof DSComponentValidation> = {
  title: 'Validation/DS Components',
  component: DSComponentValidation,
};

export default meta;

type Story = StoryObj<typeof meta>;

export const AllComponents: Story = {};

Proposta: Server Driven UI (SDUI): Um Padrão para Telas Parametrizáveis
Status: Rascunho
Versão: 1.0


                              Resumo

   Esta proposta descreve uma forma de estruturar o conteúdo das
   telas parametrizáveis (vouchers, benefícios, resgates, etc)
   de forma padronizada para reduzir a necessidade de deploy quando
   há mudanças de texto, formatação ou ordem de elementos.

   A proposta é baseada em padrões utilizados por empresas como
   Airbnb, Nubank e DoorDash, adaptados para nossa realidade.


Índice

   1. Contexto
   2. Proposta
   3. Como Funciona
      3.1. Estrutura de Tela
      3.2. Componentes
      3.3. Conteúdo Rico
      3.4. Valores e Contexto
      3.5. Regras e Condicionais
   4. Exemplo: Tela de Voucher
   5. Implementação
   6. Referências


1. Contexto

   Muitas aplicações possuem telas parametrizáveis, funcionando como 
   templates, que recebem dados do backend, definidos conforme a 
   necessidade de cada template. Na prática, os valores são dinâmicos,
   mas a estrutura não. A cada nova necessidade de alteração simples de
   layout e formatação, como destacar um texto em negrito, um novo campo é
   adicionado no JSON de resposta do servidor e uma nova regra condicional
   (if) é adicionada no frontend, resultando em armazenamento de dados legados
   e no acúmulo de código morto.

2. Proposta: Padrão SDUI.

    É um padrão arquitetural no qual o backend define a lógica de exibição 
    dos dados, indo além da definição de parâmetros textuais.

    Empresas que usam esse padrão:

        - Nubank: 70% das novas telas usam esse formato
        - Airbnb: Busca, listagens e checkout
        - DoorDash: Reduziu tempo de mudanças de semanas para horas

3. Como Funciona

3.1. Estrutura de Tela

     Uma tela é composta por:

     {
       "screen": {
         "id": "voucher_form",
         "context": { ... },      // dados para usar nos componentes
         "header": { ... },       // cabeçalho
         "body": [ ... ],         // array de componentes
         "footer": { ... }        // rodapé (botão de ação)
       }
     }

     O body é um array. A ordem do array é a ordem na tela.

3.2. Componentes

     Cada componente tem um tipo e propriedades:

     { "type": "heading", "props": { "text": "Título" } }
     { "type": "input", "props": { "label": "Valor em pontos" } }
     { "type": "button", "props": { "label": "Continuar" } }

     O app tem um registro de componentes:

     const Componentes = {
       'heading': HeadingComponent,
       'input': InputComponent,
       'button': ButtonComponent,
       'balance': BalanceComponent,
       // ...
     };

     Quando recebe o JSON, renderiza cada item do array usando
     o componente correspondente ao tipo.

     Tipos que já temos no Design System podem ser mapeados
     diretamente. Não precisa criar componentes novos.

3.3. Conteúdo Rico

     Para textos que precisam de formatação inline (negrito,
     links, ícones), usamos uma estrutura de "nodes":

     {
       "type": "rich_text",
       "children": [
         { "type": "text", "value": "Confira os " },
         { "type": "text", "value": "termos", "bold": true },
         { "type": "text", "value": " ou " },
         { "type": "link", "text": "fale conosco", "to": "app://suporte" }
       ]
     }

     Por que não markdown?

     Se usarmos [texto](url) para links e depois precisarmos
     adicionar tracking ou confirmação, temos que refatorar o
     parser.

     Com nodes, é só adicionar uma propriedade:

     {
       "type": "link",
       "text": "fale conosco",
       "to": "app://suporte",
       "trackEvent": "suporte_click"    // adicionado depois
     }

3.4. Valores e Contexto


     O Backend envia os valores no campo context:
     {
       "context": {
         "balance": {
           "points": 25720,
           "value": 7716.00
         }
       }
     }


     Para textos que dependem do contexto, usamos interpolação:

     { "type": "heading", "props": { "text": "Voucher para {{product.name}}" } }

     O app substitui {{product.name}} pelo valor do contexto.

3.5. Regras e Condicionais

     Para controlar visibilidade e habilitação, usamos regras
     simples baseadas em JSON Logic:

     Botão habilitado só quando valor > 0:

     {
       "type": "button",
       "props": {
         "label": "Continuar",
         "enabled": {
           "rule": { ">": [{ "var": "form.points" }, 0] }
         }
       }
     }

     Os operadores suportados são básicos:
     - var (acesso a dados)
     - ==, !=, >, <, >=, <= (comparação)
     - and, or, ! (lógica)

     Não tem loops, não tem eval, não tem risco.

     Validação de inputs segue o mesmo padrão:

     {
       "type": "input",
       "props": {
         "id": "points",
         "validation": {
           "rules": [
             {
               "rule": { ">": [{ "var": "value" }, 0] },
               "message": "Informe um valor maior que zero"
             }
           ]
         }
       }
     }

5. Exemplo: Tela de Voucher

   Estrutura completa para a tela de voucher:

   {
     "screen": {
       "id": "voucher_form",
       "context": {
         "product": {
           "key": "abastecimento",
           "name": "Abastecimento"
         },
         "balance": {
           "points": 25720,
           "pointsFormatted": "25.720",
           "valueFormatted": "R$ 7.716,00"
         }
       },
       "header": {
         "type": "nav_header",
         "props": {
           "title": "Voucher para {{product.name}}",
           "showBack": true
         }
       },
       "body": [
         {
           "type": "heading",
           "props": { "text": "Defina o desconto para seu {{product.key}}" }
         },
         {
           "type": "balance_display",
           "props": {
             "label": "Pontos disponíveis",
             "points": "{{balance.pointsFormatted}}",
             "value": "{{balance.valueFormatted}}"
           }
         },
         {
           "type": "points_input",
           "props": {
             "id": "points",
             "label": "Valor em pontos",
             "type": "numeric"
           }
         },
         {
           "type": "points_input",
           "props": {
             "id": "reais",
             "label": "Valor em reais",
             "type": "currency"
           }
         },
         {
           "type": "link",
           "props": {
             "text": "Exibir regras de uso",
             "to": "app://voucher/rules"
           }
         }
       ],
       "footer": {
         "type": "button",
         "props": {
           "label": "Continuar",
           "style": "primary",
           "enabled": {
             "rule": { ">": [{ "var": "form.points" }, 0] }
           }
         }
       }
     }
   }

   O mesmo código renderiza Abastecimento, Estacionamento,
   Seguro Auto e IPVA. Mudando apenas o context, não o app.


6. Implementação

   6.1. O que precisa ser feito

        - Registro de componentes (mapeamento tipo ‣ componente)
        - Renderizador que itera o array e renderiza cada tipo
        - Parser de interpolação (substituir {{var}})
        - Avaliador de regras (subset de JSON Logic)

   6.2. O que não muda

        - Design System continua o mesmo
        - Componentes existentes são reutilizados
        - Telas atuais continuam funcionando
        - Backend continua sendo Lambda que recebe/devolve JSON

   6.3. Escopo inicial

        Implementar na tela de Voucher (SPMAIS-34018) que já está
        com feature toggle. É o cenário ideal:

        - Feature nova, sem legado
        - 4 variações do mesmo fluxo
        - Retrabalho previsível (produto vai pedir ajustes)

   6.4. Validação

        O JSON pode ser validado antes de salvar no backend e
        antes de renderizar no app. Componentes desconhecidos
        usam fallback. Regras inválidas retornam false.

7. Referências

   [AIRBNB]    "A Deep Dive into Airbnb's Server-Driven UI System"
               https://medium.com/airbnb-engineering/a-deep-dive-into-airbnbs-server-driven-ui-system-842244c5f5

   [NUBANK]    "Backend Driven Content at Nubank"
               https://building.nubank.com/server-driven-ui-framework-at-nubank/

   [JSONLOGIC] JSON Logic - Regras em JSON
               https://jsonlogic.com/

