import type { SDUIContext, SDUIContextValue } from '../models';

const INTERPOLATION_REGEX = /\{\{([^}]+)\}\}/g;

export function resolveContextPath(
  context: SDUIContext,
  path: string,
): SDUIContextValue {
  const segments = path.trim().split('.');
  let current: SDUIContextValue = context;

  for (const segment of segments) {
    if (current === null || current === undefined) return '';
    if (typeof current !== 'object' || Array.isArray(current)) return '';
    current = (current as SDUIContext)[segment];
  }

  return current ?? '';
}

export function interpolateString(
  template: string,
  context: SDUIContext,
): string {
  return template.replace(INTERPOLATION_REGEX, (_, path: string) => {
    const value = resolveContextPath(context, path);
    if (value === null || value === undefined) return '';
    if (typeof value === 'object') return '';
    return String(value);
  });
}

export function interpolateDeep<T>(value: T, context: SDUIContext): T {
  if (typeof value === 'string') {
    return interpolateString(value, context) as T;
  }

  if (Array.isArray(value)) {
    return value.map(item => interpolateDeep(item, context)) as T;
  }

  if (value !== null && typeof value === 'object') {
    const result: Record<string, unknown> = {};
    for (const key of Object.keys(value)) {
      result[key] = interpolateDeep(
        (value as Record<string, unknown>)[key],
        context,
      );
    }
    return result as T;
  }

  return value;
}

