import type { SDUIContext } from '../models';
import {
  resolveContextPath,
  interpolateString,
  interpolateDeep,
} from './interpolation';

const CONTEXT: SDUIContext = {
  product: {
    key: 'abastecimento',
    name: 'Abastecimento',
    code: 206,
  },
  balance: {
    points: 25720,
    pointsFormatted: '25.720',
    value: 7716.0,
    valueFormatted: 'R$ 7.716,00',
  },
  empty: null,
  tags: ['premium', 'active'],
};

describe('resolveContextPath', () => {
  it('resolves top-level keys', () => {
    const ctx: SDUIContext = { greeting: 'hello' };
    expect(resolveContextPath(ctx, 'greeting')).toBe('hello');
  });

  it('resolves nested paths', () => {
    expect(resolveContextPath(CONTEXT, 'product.name')).toBe('Abastecimento');
    expect(resolveContextPath(CONTEXT, 'balance.pointsFormatted')).toBe(
      '25.720',
    );
  });

  it('resolves numeric values', () => {
    expect(resolveContextPath(CONTEXT, 'product.code')).toBe(206);
    expect(resolveContextPath(CONTEXT, 'balance.points')).toBe(25720);
  });

  it('returns empty string for missing paths', () => {
    expect(resolveContextPath(CONTEXT, 'nonexistent')).toBe('');
    expect(resolveContextPath(CONTEXT, 'product.missing')).toBe('');
    expect(resolveContextPath(CONTEXT, 'a.b.c.d')).toBe('');
  });

  it('returns empty string for null values', () => {
    expect(resolveContextPath(CONTEXT, 'empty')).toBe('');
  });

  it('handles whitespace in path', () => {
    expect(resolveContextPath(CONTEXT, ' product.name ')).toBe(
      'Abastecimento',
    );
  });
});

describe('interpolateString', () => {
  it('replaces single placeholder', () => {
    expect(
      interpolateString('Voucher para {{product.name}}', CONTEXT),
    ).toBe('Voucher para Abastecimento');
  });

  it('replaces multiple placeholders', () => {
    expect(
      interpolateString(
        '{{balance.pointsFormatted}} pontos = {{balance.valueFormatted}}',
        CONTEXT,
      ),
    ).toBe('25.720 pontos = R$ 7.716,00');
  });

  it('replaces numeric values as strings', () => {
    expect(
      interpolateString('Código: {{product.code}}', CONTEXT),
    ).toBe('Código: 206');
  });

  it('replaces missing values with empty string', () => {
    expect(
      interpolateString('Hello {{missing.path}}!', CONTEXT),
    ).toBe('Hello !');
  });

  it('returns original string without placeholders', () => {
    expect(interpolateString('No placeholders here', CONTEXT)).toBe(
      'No placeholders here',
    );
  });

  it('handles empty string', () => {
    expect(interpolateString('', CONTEXT)).toBe('');
  });
});

