import React from 'react';
import { View, ScrollView } from 'react-native';
import { Text, Box, SeparatorHorizontal } from '@semparar/design-system-app';
import type { Meta, StoryObj } from 'storybook/internal/types';
import type { SDUIContext } from '../services/sdui/models';
import {
  resolveContextPath,
  interpolateString,
  interpolateDeep,
} from '../services/sdui/utils/interpolation';

const VOUCHER_CONTEXT: SDUIContext = {
  product: {
    key: 'abastecimento',
    name: 'Abastecimento',
    code: 206,
  },
  balance: {
    points: 25720,
    pointsFormatted: '25.720',
    value: 7716.0,
    valueFormatted: 'R$ 7.716,00',
  },
};

function ResultRow({ label, result }: { label: string; result: string }) {
  return (
    <Box direction mb="nano" align="center">
      <Box flex={1}>
        <Text type="bodySM" color="INTENSE_COLOR_03">
          {label}
        </Text>
      </Box>
      <Box flex={1}>
        <Text type="bodyMD">{result}</Text>
      </Box>
    </Box>
  );
}

function InterpolationDemo() {
  const tests = [
    {
      label: 'resolveContextPath("product.name")',
      result: String(resolveContextPath(VOUCHER_CONTEXT, 'product.name')),
    },
    {
      label: 'resolveContextPath("balance.pointsFormatted")',
      result: String(
        resolveContextPath(VOUCHER_CONTEXT, 'balance.pointsFormatted'),
      ),
    },
    {
      label: 'resolveContextPath("missing.path")',
      result:
        `"${String(resolveContextPath(VOUCHER_CONTEXT, 'missing.path'))}"` +
        ' (empty)',
    },
    {
      label: 'interpolateString("Voucher para {{product.name}}")',
      result: interpolateString(
        'Voucher para {{product.name}}',
        VOUCHER_CONTEXT,
      ),
    },
    {
      label: 'interpolateString("{{balance.pointsFormatted}} pontos")',
      result: interpolateString(
        '{{balance.pointsFormatted}} pontos = {{balance.valueFormatted}}',
        VOUCHER_CONTEXT,
      ),
    },
  ];

  const deepInput = {
    header: { title: 'Voucher para {{product.name}}' },
    body: [
      { type: 'heading', props: { text: '{{product.name}}' } },
      {
        type: 'balance',
        props: { label: '{{balance.pointsFormatted}} pontos' },
      },
    ],
  };
  const deepResult = interpolateDeep(deepInput, VOUCHER_CONTEXT);

  return (
    <ScrollView style={{ flex: 1 }}>
      <View style={{ padding: 24, maxWidth: 600 }}>
        <Text type="headingMDL" mb="smaller">
          SDUI Interpolation — SP_0002.1
        </Text>
        <Text type="bodyMD" mb="smaller" color="INTENSE_COLOR_03">
          Validates the {'{{var}}'} replacement engine. All results below are
          computed at render time.
        </Text>
        <SeparatorHorizontal
          mb="smaller"
          bgColor="BRAND_COMPLEMENT_02"
          height={1}
          width="100%"
        />

        <Text type="subtitleXXL" mb="nano">
          resolveContextPath + interpolateString
        </Text>
        <Box pd="squishSmall" bgColor="LIGHT_BASE_02" br="sm" mb="smaller">
          {tests.map((t, i) => (
            <ResultRow key={i} label={t.label} result={t.result} />
          ))}
        </Box>

        <Text type="subtitleXXL" mb="nano">
          interpolateDeep (full object)
        </Text>
        <Box pd="squishSmall" bgColor="LIGHT_BASE_02" br="sm" mb="nano">
          <Text type="bodySM" color="INTENSE_COLOR_03" mb="nano">
            Input:
          </Text>
          <Text type="bodySM" mb="nano">
            {JSON.stringify(deepInput, null, 2)}
          </Text>
        </Box>
        <Box pd="squishSmall" bgColor="LIGHT_BASE_02" br="sm">
          <Text type="bodySM" color="INTENSE_COLOR_03" mb="nano">
            Output:
          </Text>
          <Text type="bodySM">{JSON.stringify(deepResult, null, 2)}</Text>
        </Box>
      </View>
    </ScrollView>
  );
}

const meta: Meta<typeof InterpolationDemo> = {
  title: 'SDUI/Interpolation',
  component: InterpolationDemo,
};

export default meta;

type Story = StoryObj<typeof meta>;

export const Demo: Story = {};

